using Whizbang.Core.Attributes;

namespace Whizbang.Core.AutoPopulate;

/// <summary>
/// Registration entry for an auto-populated property on a message type.
/// </summary>
/// <remarks>
/// <para>
/// This record is generated by the source generator for each property
/// decorated with an auto-populate attribute. It contains all metadata
/// needed to populate the property at runtime without reflection.
/// </para>
/// <para>
/// The specific kind enum (<see cref="TimestampKind"/>, <see cref="ContextKind"/>, etc.)
/// is set based on <see cref="PopulateKind"/>.
/// </para>
/// </remarks>
/// <docs>extending/attributes/auto-populate</docs>
public sealed record AutoPopulateRegistration {
  /// <summary>
  /// The message type containing the property.
  /// </summary>
  public required Type MessageType { get; init; }

  /// <summary>
  /// The name of the property to populate.
  /// </summary>
  public required string PropertyName { get; init; }

  /// <summary>
  /// The type of the property (e.g., DateTimeOffset?, string?, Guid?).
  /// </summary>
  public required Type PropertyType { get; init; }

  /// <summary>
  /// The category of population (determines which specific kind enum is used).
  /// </summary>
  public required PopulateKind PopulateKind { get; init; }

  /// <summary>
  /// The specific timestamp kind when <see cref="PopulateKind"/> is <see cref="AutoPopulate.PopulateKind.Timestamp"/>.
  /// </summary>
  public TimestampKind? TimestampKind { get; init; }

  /// <summary>
  /// The specific context kind when <see cref="PopulateKind"/> is <see cref="AutoPopulate.PopulateKind.Context"/>.
  /// </summary>
  public ContextKind? ContextKind { get; init; }

  /// <summary>
  /// The specific service kind when <see cref="PopulateKind"/> is <see cref="AutoPopulate.PopulateKind.Service"/>.
  /// </summary>
  public ServiceKind? ServiceKind { get; init; }

  /// <summary>
  /// The specific identifier kind when <see cref="PopulateKind"/> is <see cref="AutoPopulate.PopulateKind.Identifier"/>.
  /// </summary>
  public IdentifierKind? IdentifierKind { get; init; }
}
